//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageelbimport("testing")funcTestValidName(t*testing.T){t.Parallel()validNames:=[]string{"tf-test-elb",}for_,s:=rangevalidNames{_,errors:=ValidName(s,"name")iflen(errors)>0{t.Fatalf("%qshouldbeavalidELBname:%v",s,errors)}}invalidNames:=[]string{"tf.test.elb.1","tf-test-elb-tf-test-elb-tf-test-elb","-tf-test-elb","tf-test-elb-",}for_,s:=rangeinvalidNames{_,errors:=ValidName(s,"name")iflen(errors)==0{t.Fatalf("%qshouldnotbeavalidELBname:%v",s,errors)}}}funcTestValidNamePrefix(t*testing.T){t.Parallel()validNamePrefixes:=[]string{"test-",}for_,s:=rangevalidNamePrefixes{_,errors:=validNamePrefix(s,"name_prefix")iflen(errors)>0{t.Fatalf("%qshouldbeavalidELBnameprefix:%v",s,errors)}}invalidNamePrefixes:=[]string{"tf.test.elb.","tf-test","-test",}for_,s:=rangeinvalidNamePrefixes{_,errors:=validNamePrefix(s,"name_prefix")iflen(errors)==0{t.Fatalf("%qshouldnotbeavalidELBnameprefix:%v",s,errors)}}}